Here are pytest‑style unit tests written in plain text (no special formatting). You can copy this into a test file such as test_group_by.py.

from group_by_module import group_by  # adjust import as needed

def test_group_by_happy_path():
    items = ["a", "bb", "c", "ddd", "ee"]
    result = group_by(items, key_fn=len)
    assert result == {1: ["a", "c"], 2: ["bb", "ee"], 3: ["ddd"]}

def test_group_by_empty_list():
    result = group_by([], key_fn=lambda x: x)
    assert result == {}

def test_group_by_single_item():
    result = group_by([42], key_fn=lambda x: x % 2)
    assert result == {0: [42]}

def test_group_by_all_same_key():
    items = [1, 2, 3]
    result = group_by(items, key_fn=lambda x: 0)
    assert result == {0: [1, 2, 3]}

def test_group_by_keys_of_different_types():
    items = [1, "a", 2.5]
    def key_fn(x):
        return type(x).__name__
    result = group_by(items, key_fn)
    assert result == {
        "int": [1],
        "str": ["a"],
        "float": [2.5],
    }

def test_group_by_key_fn_raises():
    items = [1, 2, 3]
    def bad_key_fn(x):
        raise ValueError("bad key")
    try:
        group_by(items, bad_key_fn)
        assert False, "Expected ValueError"
    except ValueError as e:
        assert "bad key" in str(e)

def test_group_by_items_with_unhashable_key():
    items = [1, 2]
    def key_fn(x):
        return [x]  # lists are unhashable and cannot be dict keys
    try:
        group_by(items, key_fn)
        assert False, "Expected TypeError"
    except TypeError:
        pass
